27: class KStreamBranch<K, V> implements ProcessorSupplier<K, V, K, V> {
28: 
29:     private final List<Predicate<? super K, ? super V>> predicates;
30:     private final List<String> childNodes;
31: 
32:     KStreamBranch(final List<Predicate<? super K, ? super V>> predicates,
33:         final List<String> childNodes) {
34:         this.predicates = predicates;
35:         this.childNodes = childNodes;
36:     }
37: 
38:     @Override
39:     public Processor<K, V, K, V> get() {
40:         return new KStreamBranchProcessor();
41:     }
42: 
43:     private class KStreamBranchProcessor extends ContextualProcessor<K, V, K, V> {
44: 
45:         @Override
46:         public void process(final Record<K, V> record) {
47:             for (int i = 0; i < predicates.size(); i++) {
48:                 if (predicates.get(i).test(record.key(), record.value())) {
49:                     // use forward with child here and then break the loop
50:                     // so that no record is going to be piped to multiple streams
51:                     context().forward(record, childNodes.get(i));
52:                     return;
53:                 }
54:             }
55:             // using default child node if supplied
56:             if (childNodes.size() > predicates.size()) {
57:                 context().forward(record, childNodes.get(predicates.size()));
58:             }
59:         }
60:     }
61: }
